5120 DenseMap<const SCEV *, Value *>
5121 VPlanTransforms::expandSCEVs(VPlan &Plan, ScalarEvolution &SE) {
5122   SCEVExpander Expander(SE, "induction", /*PreserveLCSSA=*/false);
5123 
5124   auto *Entry = cast<VPIRBasicBlock>(Plan.getEntry());
5125   BasicBlock *EntryBB = Entry->getIRBasicBlock();
5126   DenseMap<const SCEV *, Value *> ExpandedSCEVs;
5127   for (VPRecipeBase &R : make_early_inc_range(*Entry)) {
5128     if (isa<VPIRInstruction, VPIRPhi>(&R))
5129       continue;
5130     auto *ExpSCEV = dyn_cast<VPExpandSCEVRecipe>(&R);
5131     if (!ExpSCEV)
5132       break;
5133     if (ExpSCEV->getNumUsers() == 0) {
5134       ExpSCEV->eraseFromParent();
5135       continue;
5136     }
5137     const SCEV *Expr = ExpSCEV->getSCEV();
5138     Value *Res =
5139         Expander.expandCodeFor(Expr, Expr->getType(), EntryBB->getTerminator());
5140     ExpandedSCEVs[ExpSCEV->getSCEV()] = Res;
5141     VPValue *Exp = Plan.getOrAddLiveIn(Res);
5142     ExpSCEV->replaceAllUsesWith(Exp);
5143     if (Plan.getTripCount() == ExpSCEV)
5144       Plan.resetTripCount(Exp);
5145     ExpSCEV->eraseFromParent();
5146   }
5147   assert(none_of(*Entry, IsaPred<VPExpandSCEVRecipe>) &&
5148          "VPExpandSCEVRecipes must be at the beginning of the entry block, "
5149          "before any VPIRInstructions");
5150   // Add IR instructions in the entry basic block but not in the VPIRBasicBlock
5151   // to the VPIRBasicBlock.
5152   auto EI = Entry->begin();
5153   for (Instruction &I : drop_end(*EntryBB)) {
5154     if (EI != Entry->end() && isa<VPIRInstruction>(*EI) &&
5155         &cast<VPIRInstruction>(&*EI)->getInstruction() == &I) {
5156       EI++;
5157       continue;
5158     }
5159     VPIRInstruction::create(I)->insertBefore(*Entry, EI);
5160   }
5161 
5162   return ExpandedSCEVs;
5163 }
