5186 static bool canNarrowOps(ArrayRef<VPValue *> Ops) {
5187   SmallVector<VPValue *> Ops0;
5188   auto *WideMember0 = dyn_cast<VPSingleDefRecipe>(Ops[0]);
5189   if (!WideMember0)
5190     return false;
5191   for (VPValue *V : Ops) {
5192     if (!isa<VPWidenRecipe, VPWidenCastRecipe>(V))
5193       return false;
5194     auto *R = cast<VPSingleDefRecipe>(V);
5195     if (getOpcodeOrIntrinsicID(R) != getOpcodeOrIntrinsicID(WideMember0))
5196       return false;
5197   }
5198 
5199   for (unsigned Idx = 0; Idx != WideMember0->getNumOperands(); ++Idx) {
5200     SmallVector<VPValue *> OpsI;
5201     for (VPValue *Op : Ops)
5202       OpsI.push_back(Op->getDefiningRecipe()->getOperand(Idx));
5203 
5204     if (canNarrowOps(OpsI))
5205       continue;
5206 
5207     if (any_of(enumerate(OpsI), [WideMember0, Idx](const auto &P) {
5208           const auto &[OpIdx, OpV] = P;
5209           return !canNarrowLoad(WideMember0, Idx, OpV, OpIdx);
5210         }))
5211       return false;
5212   }
5213 
5214   return true;
5215 }
