5217 /// Returns VF from \p VFs if \p IR is a full interleave group with factor and
5218 /// number of members both equal to VF. The interleave group must also access
5219 /// the full vector width.
5220 static std::optional<ElementCount> isConsecutiveInterleaveGroup(
5221     VPInterleaveRecipe *InterleaveR, ArrayRef<ElementCount> VFs,
5222     VPTypeAnalysis &TypeInfo, const TargetTransformInfo &TTI) {
5223   if (!InterleaveR || InterleaveR->getMask())
5224     return std::nullopt;
5225 
5226   Type *GroupElementTy = nullptr;
5227   if (InterleaveR->getStoredValues().empty()) {
5228     GroupElementTy = TypeInfo.inferScalarType(InterleaveR->getVPValue(0));
5229     if (!all_of(InterleaveR->definedValues(),
5230                 [&TypeInfo, GroupElementTy](VPValue *Op) {
5231                   return TypeInfo.inferScalarType(Op) == GroupElementTy;
5232                 }))
5233       return std::nullopt;
5234   } else {
5235     GroupElementTy =
5236         TypeInfo.inferScalarType(InterleaveR->getStoredValues()[0]);
5237     if (!all_of(InterleaveR->getStoredValues(),
5238                 [&TypeInfo, GroupElementTy](VPValue *Op) {
5239                   return TypeInfo.inferScalarType(Op) == GroupElementTy;
5240                 }))
5241       return std::nullopt;
5242   }
5243 
5244   auto IG = InterleaveR->getInterleaveGroup();
5245   if (IG->getFactor() != IG->getNumMembers())
5246     return std::nullopt;
5247 
5248   auto GetVectorBitWidthForVF = [&TTI](ElementCount VF) {
5249     TypeSize Size = TTI.getRegisterBitWidth(
5250         VF.isFixed() ? TargetTransformInfo::RGK_FixedWidthVector
5251                      : TargetTransformInfo::RGK_ScalableVector);
5252     assert(Size.isScalable() == VF.isScalable() &&
5253            "if Size is scalable, VF must be scalable and vice versa");
5254     return Size.getKnownMinValue();
5255   };
5256 
5257   for (ElementCount VF : VFs) {
5258     unsigned MinVal = VF.getKnownMinValue();
5259     unsigned GroupSize = GroupElementTy->getScalarSizeInBits() * MinVal;
5260     if (IG->getFactor() == MinVal && GroupSize == GetVectorBitWidthForVF(VF))
5261       return {VF};
5262   }
5263   return std::nullopt;
5264 }
