5274 // Convert a wide recipe defining a VPValue \p V feeding an interleave group to
5275 // a narrow variant.
5276 static VPValue *
5277 narrowInterleaveGroupOp(VPValue *V, SmallPtrSetImpl<VPValue *> &NarrowedOps) {
5278   auto *R = V->getDefiningRecipe();
5279   if (!R || NarrowedOps.contains(V))
5280     return V;
5281 
5282   if (isAlreadyNarrow(V))
5283     return V;
5284 
5285   if (isa<VPWidenRecipe, VPWidenCastRecipe>(R)) {
5286     auto *WideMember0 = cast<VPSingleDefRecipe>(R);
5287     for (unsigned Idx = 0, E = WideMember0->getNumOperands(); Idx != E; ++Idx)
5288       WideMember0->setOperand(
5289           Idx,
5290           narrowInterleaveGroupOp(WideMember0->getOperand(Idx), NarrowedOps));
5291     return V;
5292   }
5293 
5294   if (auto *LoadGroup = dyn_cast<VPInterleaveRecipe>(R)) {
5295     // Narrow interleave group to wide load, as transformed VPlan will only
5296     // process one original iteration.
5297     auto *LI = cast<LoadInst>(LoadGroup->getInterleaveGroup()->getInsertPos());
5298     auto *L = new VPWidenLoadRecipe(
5299         *LI, LoadGroup->getAddr(), LoadGroup->getMask(), /*Consecutive=*/true,
5300         /*Reverse=*/false, {}, LoadGroup->getDebugLoc());
5301     L->insertBefore(LoadGroup);
5302     NarrowedOps.insert(L);
5303     return L;
5304   }
5305 
5306   if (auto *RepR = dyn_cast<VPReplicateRecipe>(R)) {
5307     assert(RepR->isSingleScalar() &&
5308            isa<LoadInst>(RepR->getUnderlyingInstr()) &&
5309            "must be a single scalar load");
5310     NarrowedOps.insert(RepR);
5311     return RepR;
5312   }
5313 
5314   auto *WideLoad = cast<VPWidenLoadRecipe>(R);
5315   VPValue *PtrOp = WideLoad->getAddr();
5316   if (auto *VecPtr = dyn_cast<VPVectorPointerRecipe>(PtrOp))
5317     PtrOp = VecPtr->getOperand(0);
5318   // Narrow wide load to uniform scalar load, as transformed VPlan will only
5319   // process one original iteration.
5320   auto *N = new VPReplicateRecipe(&WideLoad->getIngredient(), {PtrOp},
5321                                   /*IsUniform*/ true,
5322                                   /*Mask*/ nullptr, {}, *WideLoad);
5323   N->insertBefore(WideLoad);
5324   NarrowedOps.insert(N);
5325   return N;
5326 }
