5165 /// Returns true if \p V is VPWidenLoadRecipe or VPInterleaveRecipe that can be
5166 /// converted to a narrower recipe. \p V is used by a wide recipe that feeds a
5167 /// store interleave group at index \p Idx, \p WideMember0 is the recipe feeding
5168 /// the same interleave group at index 0. A VPWidenLoadRecipe can be narrowed to
5169 /// an index-independent load if it feeds all wide ops at all indices (\p OpV
5170 /// must be the operand at index \p OpIdx for both the recipe at lane 0, \p
5171 /// WideMember0). A VPInterleaveRecipe can be narrowed to a wide load, if \p V
5172 /// is defined at \p Idx of a load interleave group.
5173 static bool canNarrowLoad(VPSingleDefRecipe *WideMember0, unsigned OpIdx,
5174                           VPValue *OpV, unsigned Idx) {
5175   VPValue *Member0Op = WideMember0->getOperand(OpIdx);
5176   VPRecipeBase *Member0OpR = Member0Op->getDefiningRecipe();
5177   if (!Member0OpR)
5178     return Member0Op == OpV;
5179   if (auto *W = dyn_cast<VPWidenLoadRecipe>(Member0OpR))
5180     return !W->getMask() && W->isConsecutive() && Member0Op == OpV;
5181   if (auto *IR = dyn_cast<VPInterleaveRecipe>(Member0OpR))
5182     return IR->getInterleaveGroup()->isFull() && IR->getVPValue(Idx) == OpV;
5183   return false;
5184 }
