5257   for (ElementCount VF : VFs) {
5258     unsigned MinVal = VF.getKnownMinValue();
5259     unsigned GroupSize = GroupElementTy->getScalarSizeInBits() * MinVal;
5260     if (IG->getFactor() == MinVal && GroupSize == GetVectorBitWidthForVF(VF))
